interface WsEnvelope {
  messageId: string;
  action: "subscribe" | "publish" | "ack" | "unsubscribe";
  resource: string; // e.g. "/feeds/user-123"
  status?: number;
}
const seen = new Set<string>();
ws.on("message", (raw: string) => {
  const msg: WsEnvelope = JSON.parse(raw);
  if (seen.has(msg.messageId)) return; // idempotency guard
  seen.add(msg.messageId);
  if (msg.action === "subscribe") {
    ws.send(JSON.stringify({ messageId: crypto.randomUUID(), status: 200, action: "ack", resource: msg.resource }));
  }
});

