// Token bucket per WebSocket connection (ws + ws library)
const buckets = new Map<WebSocket, { tokens: number; lastRefill: number }>();

const RATE = 10; // tokens per second
const CAPACITY = 30;

function consume(ws: WebSocket): boolean {
  const now = Date.now();
  const bucket = buckets.get(ws) ?? { tokens: CAPACITY, lastRefill: now };
  const elapsed = (now - bucket.lastRefill) / 1000;
  bucket.tokens = Math.min(CAPACITY, bucket.tokens + elapsed * RATE);
  bucket.lastRefill = now;
  if (bucket.tokens < 1) return false;
  bucket.tokens -= 1;
  buckets.set(ws, bucket);
  return true;
}

wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    if (!consume(ws)) {
      ws.send(JSON.stringify({ type: 'rate_limit_exceeded', retryAfter: 1000 }));
      return;
    }
    // handle message
  });
  ws.on('close', () => buckets.delete(ws));
});

