import { WebSocketServer } from 'ws';
import { pack, unpack } from 'msgpackr';

const wss = new WebSocketServer({
  port: 8080,
  perMessageDeflate: {
    serverMaxWindowBits: 10,  // 1 KB vs default 32 KB per connection
    clientMaxWindowBits: 10,
    threshold: 128,           // skip deflate for frames under 128 bytes
  },
});

wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    const msg = unpack(raw as Buffer);              // ~35% smaller than JSON
    ws.send(pack({ id: msg.id, result: handle(msg) })); // binary frame, no UTF-8 cost
  });
});

